/// <summary>
/// This class is an extension of form InventParameters
/// </summary>
[ExtensionOf(formStr(InventParameters))]
internal final class ETGInventParameters_Extension
{
}

Method.Source:
/// <summary>
/// When cylindertracking feature is enabled, then only formcontrol cylindertracking is visible.
/// </summary>
public void init()
{
    next init();

    FormRun formRun = this as FormRun;
    formRun.design().controlName(FormControlstr(InventParameters, CylinderTracking)).visible(SalesParameters::find().ETGEnableCylinderTracking);
}
